#include <iostream>
using namespace std;
bool fun(int a)
{
    if(a==2||a==0||a==1||a==9)
    {
        return true;
    }
    if(a/10==0)
    {
        return false;
    }
    return fun(a%10)||fun(a/10);
}
int main() 
{
    int n,sum=0;
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        if(fun(i))
        {
            sum+=i;
        }
    }
    cout<<sum;
    return 0;
}
